### ✅ Remplace dans `import_scenario_actions.py` par :

```python
def run(context):
    scenario_name = context.get("scenario_name")
    if not scenario_name:
        return {
            "result": False,
            "data": None,
            "message": "❌ Aucun scénario précisé dans le contexte."
        }

    action_paths = context.get("action_paths", [])
    if not action_paths:
        return {
            "result": False,
            "data": None,
            "message": f"❌ Aucun chemin d'action fourni pour le scénario '{scenario_name}'."
        }

    actions = []
    for path in action_paths:
        try:
            module_path, func_name = path.rsplit(".", 1)
            module = importlib.import_module(module_path)
            func = getattr(module, func_name)
            actions.append(func)
        except Exception as e:
            return {
                "result": False,
                "data": None,
                "message": f"❌ Erreur lors de l'import de {path} : {e}"
            }

    context["actions"] = actions
    return {
        "result": True,
        "data": actions,
        "message": f"✅ {len(actions)} actions importées pour le scénario '{scenario_name}'"
    }
```

