# Fichier : config.py
import os

class Config:
    """
    Classe centrale pour gérer la configuration actuelle.
    Elle peut être initialisée avec des données par défaut ou injectées depuis une base de données.
    """

    # Valeurs par défaut si aucun projet n'est sélectionné
    DEFAULTS = {
        "PROJECT_TYPE": "site",
        "ENV": "local",
        "CLIENT": "laNostrAI",
        "PROJECT_NAME": "default_core",
        "DB_NAME": "default_core.db",
    }

    _current_config = DEFAULTS.copy()

    @classmethod
    def get(cls, key):
        """Récupère une valeur de configuration (priorité aux variables d'environnement)."""
        return os.getenv(key, cls._current_config.get(key))

    @classmethod
    def set(cls, key, value):
        """Modifie dynamiquement une valeur de configuration."""
        cls._current_config[key] = value

    @classmethod
    def set_bulk(cls, config_dict):
        """Injecte un ensemble de paramètres à la configuration."""
        cls._current_config.update(config_dict)

    @classmethod
    def all(cls):
        """Retourne toutes les variables de configuration courantes."""
        return cls._current_config.copy()

    @classmethod
    def reset(cls):
        """Réinitialise la configuration aux valeurs par défaut."""
        cls._current_config = cls.DEFAULTS.copy()
```

---

### ✅ Fonctionnement prévu :
- `Config.get("DB_NAME")` → `"default_core.db"` (si non surchargé par env)
- `Config.set("PROJECT_NAME", "super_app")`
- `Config.set_bulk({...})` pour injecter tout un `dict`
- `Config.reset()` pour revenir aux valeurs par défaut

